questionvariables.text:
/* Q2: Wave Parameters Across Two Media + Reflection */
idx: 1 + rand(5);
f_GHz: [0.9, 1.8, 2.4, 5.0, 10.0][idx];
eps_r1: [1, 2, 1, 3, 2][idx];
eps_r2: [4, 9, 6, 9, 12][idx];

c0: 3*10^8;
eta_0: 120*%pi;
f_Hz: f_GHz * 10^9;

tans1: float(c0 / sqrt(eps_r1));
tans2: float(tans1 / f_Hz);
tans3: float(2*%pi / tans2);
tans4: float(ev(eta_0 / sqrt(eps_r1), numer));
tans5: float(ev(eta_0 / sqrt(eps_r2), numer));
tans6: float((tans5 - tans4) / (tans5 + tans4));
tans7: float(tans6^2);

/* Error models */
Gamma_swapped: float((tans4 - tans5) / (tans4 + tans5));
vp1_err: if eps_r1 > 1 then float(c0 / eps_r1) else 0;
Gamma_abs: float(abs(tans6));

/* (h) Transmitted power fraction */
tans8: float(1 - tans7);

/* (i) Impedance matching MCQ — if eps_r2 = eps_r1, Gamma = 0 */
ta9: random_permutation([
  [1, true, "No power is reflected — the boundary becomes invisible to the wave"],
  [2, false, "All power is reflected — the wave cannot enter the second medium"],
  [3, false, "Half the power is reflected"],
  [4, false, "The result depends on the frequency"]
]);
correct_i: 1;

/* (j) Effect of increasing eps_r2 on reflected power */
ta10: random_permutation([
  [1, true, "Increases — larger permittivity mismatch causes more reflection"],
  [2, false, "Decreases — denser material absorbs more of the wave"],
  [3, false, "Stays the same — reflection depends only on frequency"],
  [4, false, "First increases, then decreases"]
]);
correct_j: 1;

feedbackvariables.text:
s_sum: ans4 + ans5;
s_Gamma: if is(abs(s_sum) > 0.01) then float((ans5 - ans4)/s_sum) else 0;
method_ok: if is(abs(s_sum) > 0.01) and is(abs(ans6 - s_Gamma) < 0.02) then 1 else 0;
swap_ok: if is(abs(tans6) > 0.001) and is(abs(ans6 - Gamma_swapped)/abs(Gamma_swapped) < 0.06) then 1 else 0;
